import{_ as e,a as t,b as i}from"./chunks/支持留言.NiGCLVdp.js";import{_ as l,o as s,c as o,a2 as p}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"ブログ機能の使い方","description":"","frontmatter":{},"headers":[],"relativePath":"ja-JP/Other/blog.md","filePath":"ja-JP/Other/blog.md","lastUpdated":1781962217000}'),n={name:"ja-JP/Other/blog.md"};function d(r,a,c,h,g,b){return s(),o("div",null,[...a[0]||(a[0]=[p('<h1 id="ブログ機能の使い方" tabindex="-1">ブログ機能の使い方 <a class="header-anchor" href="#ブログ機能の使い方" aria-label="Permalink to &quot;ブログ機能の使い方&quot;">​</a></h1><p>ブログ機能を有効にすると、ImgBed サイトに独立したブログページを追加できます。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://あなたのドメイン/blog/</span></span></code></pre></div><p><img src="'+e+'" alt="ブログトップ" loading="lazy"></p><p>このブログ機能は <a href="https://github.com/LyraVoid/Mizuki" target="_blank" rel="noreferrer">LyraVoid/Mizuki</a> を参考に、ImgBed 向けに Vue で組み込み直したものです。</p><h2 id="設定場所" tabindex="-1">設定場所 <a class="header-anchor" href="#設定場所" aria-label="Permalink to &quot;設定場所&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>システム設定 -&gt; その他の設定 -&gt; ブログ</span></span></code></pre></div><p><img src="'+t+'" alt="ブログ設定" loading="lazy"></p><h2 id="初回設定" tabindex="-1">初回設定 <a class="header-anchor" href="#初回設定" aria-label="Permalink to &quot;初回設定&quot;">​</a></h2><ol><li>「有効」をオンにします。</li><li>ブログ設定を保存する GitHub アカウントを選びます。</li><li>「ブログを更新」をクリックします。</li><li>更新完了のメッセージを待ちます。</li><li><code>https://あなたのドメイン/blog/</code> を開いて確認します。</li></ol><p>初回は、選択した GitHub アカウントに次のプライベートリポジトリが作成されます。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>このリポジトリにブログ設定と記事データが保存されます。</p><h2 id="記事を書く場所" tabindex="-1">記事を書く場所 <a class="header-anchor" href="#記事を書く場所" aria-label="Permalink to &quot;記事を書く場所&quot;">​</a></h2><p>記事は GitHub の <code>imgbed-blog-config</code> リポジトリで編集します。</p><p>基本の流れは次のとおりです。</p><ol><li>GitHub を開きます。</li><li><code>imgbed-blog-config</code> に入ります。</li><li>記事ファイルを追加または編集します。</li><li>変更をコミットします。</li><li>ImgBed の管理画面で「ブログを更新」を押します。ブログトップ左上のロゴを 3 回クリックして更新することもできます。</li></ol><p>「ブログを更新」は、すでに書いた記事を上書きする操作ではありません。初期化やキャッシュ更新のために使います。</p><h2 id="利用できる機能" tabindex="-1">利用できる機能 <a class="header-anchor" href="#利用できる機能" aria-label="Permalink to &quot;利用できる機能&quot;">​</a></h2><p>記事一覧、カテゴリ、タグ、アーカイブ、検索、ダークモード、多言語切り替えに対応しています。</p><p>コメントとアクセス統計も利用できます。</p><p><img src="'+i+'" alt="ブログコメント" loading="lazy"></p><p>コメントは記事ページの下に表示されます。訪問者はアバター、ニックネーム、メールアドレス、コメント内容を入力して投稿できます。</p><p>アクセス統計では記事閲覧数やサイト訪問数を確認できます。</p><h2 id="公開-url" tabindex="-1">公開 URL <a class="header-anchor" href="#公開-url" aria-label="Permalink to &quot;公開 URL&quot;">​</a></h2><p>ブログは常に <code>/blog/</code> 配下で公開されます。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com/blog/</span></span></code></pre></div><p>ブログを無効にすると、訪問者はブログページにアクセスできなくなります。</p>',28)])])}const k=l(n,[["render",d]]);export{_ as __pageData,k as default};
